PictureData.Code:
let actor = $gameParty.battleMembers()[0];

const emptyPixel = "data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=";

if (!actor) return emptyPixel;

let aName = actor.name().replace(/\\[a-zA-Z]+\[.*?\]/g, '').replace(/[\x00-\x1F\x7F-\x9F]/g, '').trim().toLowerCase();

if (aName === "") return emptyPixel;

let stateStr = "neutral";

if (actor.isDead()) {
    stateStr = "sleep";
} else if (actor.isStateAffected(3)) {
    stateStr = "heroic";
} else if (actor.isStateAffected(4)) {
    stateStr = "frantic";
} else if (actor.isStateAffected(5)) {
    stateStr = "hopeless";
} else if (actor.isStateAffected(6)) {
    stateStr = "martyr";
} else if (actor.isStateAffected(7)) {
    stateStr = "hysterical";
} else if (actor.isStateAffected(8)) {
    stateStr = "despair";
}

return "img/pictures/" + aName + "_" + stateStr + "_state.png";

